declare type Snap = {
    [key: string]: any;
};
declare type Reducer = (payload: Snap) => Snap;
declare type GetSnap = (model?: Model) => Snap;
declare type SetSnap = (payload: Snap | Reducer) => void;
declare type Model = ({ get, set }: {
    get: GetSnap;
    set: SetSnap;
}) => Snap;
declare type UseModel = (model: Model) => Snap;
declare const useModel: UseModel;

export { Model, useModel as default };
